import{_ as e,o as l,c as i,ag as t}from"./chunks/framework.DNt_9s2P.js";const u=JSON.parse('{"title":"時間割","description":"","frontmatter":{},"headers":[],"relativePath":"guide/timetable.md","filePath":"guide/timetable.md"}'),o={name:"guide/timetable.md"};function r(n,a,p,h,d,s){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="時間割" tabindex="-1">時間割 <a class="header-anchor" href="#時間割" aria-label="Permalink to &quot;時間割&quot;">​</a></h1><p>KWIC と Luna のデータを統合した週間時間割ビューです。</p><h2 id="グリッド表示" tabindex="-1">グリッド表示 <a class="header-anchor" href="#グリッド表示" aria-label="Permalink to &quot;グリッド表示&quot;">​</a></h2><p>月曜日から土曜日、1 限から 7 限までのグリッド形式で時間割を表示します。</p><ul><li>KWIC に登録された正規の授業</li><li>Luna のコース情報</li><li>シラバスお気に入りのオーバーレイ表示</li></ul><p>各セルをクリックすると、授業の詳細情報を確認できます。</p><h2 id="週単位ナビゲーション" tabindex="-1">週単位ナビゲーション <a class="header-anchor" href="#週単位ナビゲーション" aria-label="Permalink to &quot;週単位ナビゲーション&quot;">​</a></h2><p>前週 / 次週ボタンで週を切り替えられます。休講・補講・教室変更がある場合は、該当するセルにマークが表示されます。</p><h2 id="試験時間割" tabindex="-1">試験時間割 <a class="header-anchor" href="#試験時間割" aria-label="Permalink to &quot;試験時間割&quot;">​</a></h2><p>試験期間中は、通常の時間割に加えて試験時間割の表示に切り替えることができます。</p><h2 id="カレンダー同期" tabindex="-1">カレンダー同期 <a class="header-anchor" href="#カレンダー同期" aria-label="Permalink to &quot;カレンダー同期&quot;">​</a></h2><p>時間割を外部カレンダーに自動エクスポートできます。</p><h3 id="apple-カレンダー-macos" tabindex="-1">Apple カレンダー（macOS） <a class="header-anchor" href="#apple-カレンダー-macos" aria-label="Permalink to &quot;Apple カレンダー（macOS）&quot;">​</a></h3><p>macOS ネイティブの EventKit を使用して、Apple カレンダーに直接イベントを作成します。</p><ul><li>変更検知による差分同期（追加・変更・削除を自動反映）</li><li>初回同期時にカレンダーアクセスの権限許可が必要です</li></ul><h3 id="google-カレンダー" tabindex="-1">Google カレンダー <a class="header-anchor" href="#google-カレンダー" aria-label="Permalink to &quot;Google カレンダー&quot;">​</a></h3><p>Google Calendar API を使用して同期します。</p><ul><li>Google アカウントとの OAuth 連携が必要です</li><li>差分同期に対応</li></ul><h2 id="ai-履修分析" tabindex="-1">AI 履修分析 <a class="header-anchor" href="#ai-履修分析" aria-label="Permalink to &quot;AI 履修分析&quot;">​</a></h2><p>OpenAI / Gemini API を使い、成績・履修状況・シラバスを基に履修アドバイスレポートを生成します。</p><ul><li>卒業要件に対する進捗の可視化</li><li>おすすめ科目の提案</li><li>履修バランスの分析</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>AI 履修分析を使用するには、設定画面で API キーを登録する必要があります。</p></div>',22)])])}const m=e(o,[["render",r]]);export{u as __pageData,m as default};
